code = """import pandas as pd
import json

# Load variables from storage
cases = var_call_oMt1y0xQ7bK1AZC6dIkO4FCQ
assign_counts = var_call_qnQf0CVD5rsIeWFThwWzy0kK
assignments = var_call_oaqI4oo92VH3KnS3Vr0eLrLw

# Helpers
def clean_id(x):
    if x is None:
        return None
    s = str(x).strip()
    if s.startswith('#'):
        s = s[1:]
    return s

# Create DataFrames
cases_df = pd.DataFrame(cases)
if cases_df.empty:
    cases_df = pd.DataFrame(columns=['id','createddate','closeddate'])
# Clean ids and dates
cases_df['id'] = cases_df['id'].apply(clean_id)
# Convert 'None' strings to None
cases_df['closeddate'] = cases_df['closeddate'].replace({'None': None})
cases_df['createddate'] = pd.to_datetime(cases_df['createddate'])
cases_df['closeddate'] = pd.to_datetime(cases_df['closeddate'])

assign_counts_df = pd.DataFrame(assign_counts)
if assign_counts_df.empty:
    assign_counts_df = pd.DataFrame(columns=['caseid__c','assign_count'])
assign_counts_df['caseid__c'] = assign_counts_df['caseid__c'].apply(clean_id)
assign_counts_df['assign_count'] = assign_counts_df['assign_count'].astype(int)

assignments_df = pd.DataFrame(assignments)
if assignments_df.empty:
    assignments_df = pd.DataFrame(columns=['id','caseid__c','oldvalue__c','newvalue__c','createddate','field__c'])
assignments_df['caseid__c'] = assignments_df['caseid__c'].apply(clean_id)
assignments_df['newvalue__c'] = assignments_df['newvalue__c'].apply(clean_id)
assignments_df['createddate'] = pd.to_datetime(assignments_df['createddate'])

# Merge cases with assign counts
merged = cases_df.merge(assign_counts_df, left_on='id', right_on='caseid__c', how='left')
# Keep only cases that have exactly one owner assignment (not transferred) and have closeddate
filtered_cases = merged[(merged['assign_count'] == 1) & (merged['closeddate'].notna())].copy()

# For these cases, find the owner (from assignments_df)
# There should be an assignment entry in assignments_df for each case in the window
owners = assignments_df[['caseid__c','newvalue__c']].drop_duplicates()
owners.rename(columns={'caseid__c':'id','newvalue__c':'ownerid'}, inplace=True)
owners['id'] = owners['id'].apply(clean_id)
owners['ownerid'] = owners['ownerid'].apply(clean_id)

filtered_cases = filtered_cases.merge(owners, on='id', how='left')

# Compute handle time in seconds
filtered_cases['handle_seconds'] = (filtered_cases['closeddate'] - filtered_cases['createddate']).dt.total_seconds()

# Compute assigned_case_count per agent from assignments_df within the window
assigned_counts = assignments_df.groupby('newvalue__c')['caseid__c'].nunique().reset_index()
assigned_counts.columns = ['ownerid','assigned_case_count']
assigned_counts['ownerid'] = assigned_counts['ownerid'].apply(clean_id)

# Compute average handle time per agent using filtered_cases where ownerid matches
agent_avg = filtered_cases.groupby('ownerid')['handle_seconds'].mean().reset_index()
agent_avg.columns = ['ownerid','avg_handle_seconds']

# Combine with assigned_counts and filter agents who processed more than one case (>1)
agent_stats = assigned_counts.merge(agent_avg, on='ownerid', how='left')
agent_stats = agent_stats[agent_stats['assigned_case_count'] > 1].copy()
# Exclude agents with no avg_handle_seconds (NaN)
agent_stats = agent_stats[agent_stats['avg_handle_seconds'].notna()]

# If no agent qualifies, return empty
if agent_stats.empty:
    result = None
else:
    # Find agent with lowest average handle time
    best = agent_stats.loc[agent_stats['avg_handle_seconds'].idxmin()]
    result = best['ownerid']

print("__RESULT__:")
print(json.dumps(result))"""

